        result.add(deleteChar(s, c));
        result.add(isPalindrome((String) result.get(0)));
        return result;
    }

    public boolean isPalindrome(String str){
        int length = str.length();
        int forward = 0;
        int backward = length - 1;
        while (backward > forward) {
            char forwardChar = str.charAt(forward++);
            char backwardChar = str.charAt(backward--);
            if (forwardChar != backwardChar)
                return false;
        }
        return true;
    }

    public String deleteChar(String str, String remove){
        if (str == null || str.length() <= 0 || str.equals(remove)) {
            return "";
        }
        return str.replaceAll(remove, "");
    }

